import microcoapy

class Device(microcoapy.Server):
    def __init__(self, resource_dir):
        super().__init__()
        self.resource_dir = resource_dir

    async def handle_get(self, context):
        if context.uri == '/sensors/temp':
            return await self.respond('27')
        elif context.uri == '/actuators/light':
            return await self.respond('off')
        else:
            return await self.not_found()

    async def handle_put(self, context):
        if context.uri == '/actuators/light':
            value = await context.payload.read()
            if str(value).lower() in ['on', 'off']:
                return await self.respond('acknowledged')
        return await self.not_found()

